const moveInterval = setInterval(() => {
    const sectionPaypal = document.querySelector('.section-paypalbutton');
    const paypalGpay = document.querySelector('#paypal-gpay-buttons');

    if (sectionPaypal && paypalGpay) {
        sectionPaypal.appendChild(paypalGpay);
        clearInterval(moveInterval);
    }
}, 200);

var checkJq = setInterval(function() {
  if (window.jQuery && typeof jQuery.fn.slideToggle === 'function') {
    clearInterval(checkJq);
    $("#innerButton1").on("click",function(){
    app.model.discount10 = true
    app.closeDiscount()
})
    function randomInt(min, max) {
      return Math.floor(Math.random() * (max - min + 1)) + min;
    }
    $(".section-hight span").text(randomInt(63,200))

    $(".section-order-summary").on("click", function() {
      $(".summary-content").stop().slideToggle(500);
      $(this).toggleClass("open");
    });
    $("#extended").on("click", function () {
  $("#coverage-case").trigger("click");
$("#warrantyDisplay").toggle()

});
    const target = $(".checkout-page-cart-price-section .total_price")[0];

const observer = new MutationObserver(function (mutationsList) {
  for (let mutation of mutationsList) {
    if (mutation.type === "characterData" || mutation.type === "childList") {
      let total = $(".checkout-page-cart-price-section .total_price").text();
      let save_price = $(".checkout-page-cart-price-section .save_price").text();

      $(".section-order-summary .subtotal").text(total);
      $(".section-order-summary .total_price").text(total);
      let new_price = $("div#Choose-your-package-section .active .offer-price").text().replace(/\/ea/g, '');
      $("#mainSummery .sumitemPrice").text(new_price);
      $(".section-special .item-price").text(new_price);
      $(".section-special .item-save-price span").text(save_price);

      if ($('#extended').is(':checked')) {
        save_price = save_price.replace(/\$/g, '');
        save_price = parseFloat(save_price) + (29.99 - 9.95);
        save_price = "$"+save_price.toFixed(2);
      }
      $(".section-order-summary .sumyousave").text(save_price);

    }
  }
});

observer.observe(target, {
  childList: true,
  characterData: true,
  subtree: true
});
  }
}, 200);
