(function() {
  // 1. CREATE BUTTON
  const button = document.createElement('button');
  button.className = 'submit-button-universal'; 
  button.textContent = 'BUY NOW';

  // 2. INSERT BUTTON
  // Using the DriveBright container selector
  const stepWrapper = document.querySelector('[data-os-id="air-cooler-packages"]');
  if (stepWrapper) {
    stepWrapper.insertAdjacentElement('afterend', button);
  } else {
    // Fallback: Try finding the last card or generic container if ID is missing
    const lastCard = document.querySelector('.os-cards__vertical');
    if(lastCard) lastCard.insertAdjacentElement('afterend', button);
  }

  // 3. SCROLL FUNCTION (Same as your working floating code)
  function scrollToShipping() {
    // A. Find the form container
    const target = document.querySelector('.checkout-form') || document.querySelector('form');
    
    // B. Find "Shipping" text if form container isn't obvious
    const targetFallback = target || Array.from(document.querySelectorAll('h2, h3, h4, div'))
                                          .find(el => el.innerText.includes('Shipping'));

    if (targetFallback) {
      // C. The Offset: Lands 120px above the target to show the header text
      const yOffset = -120; 
      const y = targetFallback.getBoundingClientRect().top + window.pageYOffset + yOffset;

      window.scrollTo({
        top: y,
        behavior: 'smooth'
      });
    }
  }

  // 4. CLICK LISTENER
  button.addEventListener('click', function(e) {
    e.preventDefault();
    scrollToShipping();
  });

})();
